VALUES
  ('social-worker-moex-06640', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會工作組織可運用目標管理的程序，對達到該結果需那些資源以及達成的期限等有所共識，而目標管 理可參考SMART原則來決定，其中M的意義是：', '["可標記的", "可測量的", "可行銷性", "具激勵性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06641', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '成本效益評估（cost benefit analysis）屬於經濟評估的一環，該類評估重視方案是否以合理的價格達到目 標，或是否能以較低的支出成本獲得同樣的結果。下列那一個敘述屬於成本效益評估的論述？', '["因強調經濟效率，故更能彰顯公平性", "可以不考慮時間價值", "其主張評估變數處在不完全自由的市場", "著重分析投入於方案成本與其產出之間的關係"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06642', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '進行成效導向的方案規劃適合運用在創新性方案，而在方案規劃之前，個人及組織應該具備的思維與準 備為何？', '["不需要有工作時間表", "獲得參與者的共識並釐清職責", "強調個人能力，單打獨鬥即可以完成規劃", "不需決策者的支持也可以進行規劃"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06643', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會工作方案所提出的目標（objective）與目的（goal）呈現方式不同，下列對目標（objective）敘述何 者較為正確？', '["「本方案在2014年底前預計提升受服務者之健康水準與生活品質」是目標的寫法", "目標（objective）是僅有方向感即可", "目標（objective）極重視宣示效果，以利方案爭取相關支持", "目標（objective）需有時間架構與改變內容以利檢視等"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06644', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會工作組織如果強調目標通常由主管設定、目標達成的重要性與強調規則、程序和制度等，是下列何 種管理模式？', '["目標管理", "傳統管理", "參與式管理", "走動式管理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06645', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '依據民國98年4月17日行政院修正行政院所屬各機關中長程個案計畫編審要點規定，其中關於長程及 中程之年限，下列何者為正確？', '["以業務功能別，依據長程施政目標，訂定期程超過七年之個案計畫為長程個案計畫", "以業務功能別，依據長程施政目標，訂定期程超過十年之個案計畫為長程個案計畫", "以業務功能別，依據各機關中程施政計畫，並配合長程個案計畫，訂定期程為三年至六年之個案計畫 為中程個案計畫", "以業務功能別，依據各機關中程施政計畫，並配合長程個案計畫，訂定期程為二年至六年之個案計畫 為中程個案計畫"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06646', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會工作管理實務的運作必需檢視績效，對於責信的概念深具意義，下列何者為績效監測功能之一？', '["可徵詢意見", "可與他機構競爭", "可對員工賞罰", "可與同仁競爭"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06647', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會服務領域的夥伴關係仍有些值得強調的共同特性，下列敘述何者正確？', '["逐步市場化的結合", "競爭與互惠併存", "片斷性服務", "綜效或增值"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06648', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '一般而言，組織進行網絡治理的概念具有幾項特點，下列敘述何者較為正確？', '["組織之間的獨立與自主", "由於需要相互交換資源與協商共同的目標，網絡成員之間的互動持續進行", "以競爭為基礎之賽局的（game-like）互動關係", "自主式的網絡不須對國家負責，但國家仍要居於主權的立場以直接引導網絡"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06649', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '當前治理的範疇已非僅侷限於政府的活動，治理模式是一種比政府範圍更為廣泛的現象，故不管是公部 門、非營利或營利組織的社會福利管理者，必須在合作過程中發揮其運作之功能。其中Thompson等 人（1991）提出三種治理模式，請問為那三種？', '["科層模式、市場模式、網絡模式", "科層模式、市場模式、水平模式", "夥伴模式、水平模式、市場模式", "科層模式、水平模式、網絡模式"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
